TOOLS = [
    {
        "name": "introspect_schema",
        "description": (
            "List columns and types for one or all tables. "
            "Always call this first before writing SQL to verify table and column names."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "table_name": {
                    "type": "string",
                    "description": "Table name to inspect. Omit to list all tables."
                }
            },
            "required": [],
        },
    },
    {
        "name": "run_sql",
        "description": (
            "Execute a read-only SELECT query and return a preview of the result. "
            "Do NOT use for INSERT/UPDATE/DELETE/DROP."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Valid SQL SELECT statement."},
                "max_rows": {"type": "integer", "description": "Row limit, default 50."}
            },
            "required": ["query"],
        },
    },
    {
        "name": "run_python",
        "description": (
            "Execute pandas/Python code for transforms that are awkward in SQL. "
            "DataFrames loaded via run_sql are available by name."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {"type": "string", "description": "Python code to execute."}
            },
            "required": ["code"],
        },
    },
    {
        "name": "compute_stats",
        "description": "Compute descriptive statistics (mean, std, min/max, percentiles) for a DataFrame.",
        "input_schema": {
            "type": "object",
            "properties": {
                "df_name": {"type": "string", "description": "Name of the DataFrame in scope."}
            },
            "required": ["df_name"],
        },
    },
]

import anthropic

client = anthropic.Anthropic()

SYSTEM = """You are a data analysis agent.
Available data: a SQLite database with tables: orders(id, user_id, created_at, amount, status).

Workflow:
1. Introspect schema to confirm column names.
2. Write and run the appropriate SELECT query.
3. Summarise the result in plain language.
4. Stop — do not attempt to write data or create tables.
"""

def run_agent(question: str, engine) -> str:
    df_store: dict = {}

    def dispatch(name: str, args: dict) -> str:
        if name == "introspect_schema":
            return introspect_schema(engine, args.get("table_name"))
        if name == "run_sql":
            return run_sql(engine, args["query"], args.get("max_rows", 50))
        if name == "run_python":
            return run_python(df_store, args["code"])
        if name == "compute_stats":
            return compute_stats(df_store, args["df_name"])
        return f"Unknown tool: {name}"

    messages = [{"role": "user", "content": question}]

    for _ in range(10):  # max 10 turns
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            text_blocks = [b for b in response.content if b.type == "text"]
            return text_blocks[-1].text if text_blocks else ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                output = dispatch(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output,
                })
        messages.append({"role": "user", "content": tool_results})

    return "Max turns reached without a final answer."
